if(fpcm===void 0)var fpcm={};fpcm.filemanager.listActions={init:function(){fpcm.dom.bindClick("a.btn[data-insert-type]",function(e,t){let n=new URLSearchParams(window.location.search),s=n.get("m")==="media",o=n.get("m")==="file";if(!o&&!s&&t.dataset.insertType==="video"){fpcm.ui.addMessage({txt:"FILE_LIST_INSERT_FAILED_IMAGE",type:"neutral"});return}if(!o&&s&&t.dataset.insertType==="image"){fpcm.ui.addMessage({txt:"FILE_LIST_INSERT_FAILED_VIDEO",type:"neutral"});return}switch(t.dataset.insertFn){case"thumb":parent.fpcm.editor.insertThumbByEditor(t.href,t.dataset.imgtext);break;case"full":parent.fpcm.editor.insertFullByEditor(t.href,t.dataset.imgtext);break;case"articleimg":parent.document.getElementById("articleimagepath").value=t.href;break;case"poster-thumb":parent.document.getElementById(fpcm.ui.prepareId("mediaposter",!0)).value=t.href;break;case"poster-full":parent.document.getElementById(fpcm.ui.prepareId("mediaposter",!0)).value=t.href;break;case"video":parent.fpcm.editor.insertFullByEditor(t.href,t.href);break}fpcm.ui_dialogs.close("editor-html-filemanager",!0)}),fpcm.dom.bindClick("#btnInsertGallery",function(){let e=document.querySelectorAll(".fpcm-ui-list-checkbox[data-type=image]:checked");return!!e&&!!e.length&&(parent.fpcm.editor.insertGalleryByEditor(e),!1)})},initListActions:function(){fpcm.filemanager.initInsertButtons()}}